import { Input } from '../Input/Input'
import { ListWrapper, TasksList } from './List.styles'
import { Task } from '../Task/Task'
import { useState } from 'react'


export const List = () => {
  const [tasks, setTasks] = useState([])

  return (
    <ListWrapper>
      <Input add/>

      <TasksList>
        {tasks.map((item) => (
          <Task task={item} key={item.id} />
        ))}
      </TasksList>
    </ListWrapper>
  )
}
